#include <iostream>
using namespace std;
class Solution {
public:
    int fib(int n) {
        if (n == 0) {
            return 0;
        }
        int prev = 0, curr = 1;
        for (int i = 2; i <= n; i++) {
            int next = prev + curr;
            prev = curr;
            curr = next;
        }
        return curr;
    }
};
int main() {
    int n;
    cin >> n;
    Solution s;
    cout << s.fib(n) << endl;
    return 0;
}
